+    ASSERT_EQ(asx_region_open(&parent), ASX_OK);
+    ASSERT_EQ(asx_region_open_child(parent, &child1), ASX_OK);
+    ASSERT_EQ(asx_region_open_child(parent, &child2), ASX_OK);
+    ASSERT_EQ(asx_region_open_child(parent, &child3), ASX_OK);
