+    ASSERT_EQ(asx_region_slot_lookup(child1, &child_slot), ASX_OK);
+    ASSERT_EQ(child_slot->parent_id, parent);
+    ASSERT_EQ(asx_region_slot_lookup(child2, &child_slot), ASX_OK);
